import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void allZeros() {
        assertEquals(0L, new Solution().ipToLong("0.0.0.0"));
    }

    @Test
    void loopback() {
        assertEquals(2130706433L, new Solution().ipToLong("127.0.0.1"));
    }

    @Test
    void privateRange() {
        assertEquals(3232235777L, new Solution().ipToLong("192.168.1.1"));
    }

    @Test
    void allOnes() {
        // Maximum IPv4 вҖ” all 32 bits set; must not overflow (requires long, not int)
        assertEquals(4294967295L, new Solution().ipToLong("255.255.255.255"));
    }

    @Test
    void broadcastSingleOctetMax() {
        // 0.0.0.255 вҖ” only last octet non-zero
        assertEquals(255L, new Solution().ipToLong("0.0.0.255"));
    }

    @Test
    void firstOctetOnly() {
        // 1.0.0.0 = 1 << 24
        assertEquals(16777216L, new Solution().ipToLong("1.0.0.0"));
    }
}
